#include <stdio.h>
#include <stdlib.h>

int minBribes(int* arr, int n, int k) {
    int bribes = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - 1; j++) {
            if (arr[j] > arr[j + 1] && abs(arr[j] - arr[j + 1]) <= k) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
                bribes++;
            }
        }
    }
    return bribes;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int h, k;
        scanf("%d %d", &h, &k);
        int n = 1 << h;
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int bribes = minBribes(arr, n, k);
        printf("%d\n", bribes);
        free(arr);
    }
    return 0;
}

