#include <iostream>
#include <vector>
#include <algorithm>

int minBribes(std::vector<int>& arr, int k) {
    int bribes = 0;
    for (int i = 0; i < arr.size(); i++) {
        for (int j = 0; j < arr.size() - 1; j++) {
            if (arr[j] > arr[j + 1] && abs(arr[j] - arr[j + 1]) <= k) {
                std::swap(arr[j], arr[j + 1]);
                bribes++;
            }
        }
    }
    return bribes;
}

int main() {
    int t;
    std::cin >> t;
    while (t--) {
        int h, k;
        std::cin >> h >> k;
        int n = 1 << h;
        std::vector<int> arr(n);
        for (int i = 0; i < n; i++) {
            std::cin >> arr[i];
        }
        int bribes = minBribes(arr, k);
        std::cout << bribes << std::endl;
    }
    return 0;
}

