import java.util.Scanner;

public class Main {
    public static int minBribes(int[] arr, int k) {
        int bribes = 0;
        for (int i = 0; i < arr.length; i++) {
            for (int j = 0; j < arr.length - 1; j++) {
                if (arr[j] > arr[j + 1] && Math.abs(arr[j] - arr[j + 1]) <= k) {
